import { RequireService } from './require.interface'
import { Injectable } from '@angular/core'
import { HttpClient } from '@angular/common/http'

/**
 * Fetches a bundle from a target url.
 *
 * @export
 */
@Injectable()
export class HttpRequireService implements RequireService {

    constructor(private httpClient: HttpClient){}

    load(url) : Promise<Object> {
        return this.httpClient.get(url).toPromise()
            .then(data => data);
    }

}

import {throwError as observableThrowError, Observable} from 'rxjs';
import {Injectable} from '@angular/core';

@Injectable()
export class InputFileService {
    public validateFiles(files: FileList, maxFilesNumber: number, allowedExtensions: string[]): Observable<File[]> {
        if (!files) {
            return observableThrowError('files is empty');
        }
        if (files.length > maxFilesNumber) {
            return observableThrowError(`Only ${maxFilesNumber} file(s) allowed`);
        }

        const validFiles: File[] = [];
        const invalidFiles: File[] = [];
        for (let i = 0; i < files.length; i++) {
            const filenameSplit = files[i].name.split('.');
            const ext = filenameSplit[filenameSplit.length - 1];
            if (allowedExtensions.lastIndexOf(ext.toLowerCase()) !== -1) {
                validFiles.push(files[i]);
            } else {
                invalidFiles.push(files[i]);
            }
        }

        return new Observable(observer => {
            if (validFiles.length > 0) {
                observer.next(validFiles);
            }
            if (invalidFiles.length > 0) {
                observer.error(`Extension not allowed. Allowed extensions: ${allowedExtensions}`);
            }
            observer.complete();
        });
    }

    public isSrcExternalUrl(src: string): boolean {
        if (src) {
            return src.startsWith('http://') || src.startsWith('https://');
        } else {
            return false;
        }
    }

    public isSrcWorkspace(src: string): boolean {
        if (src) {
            return src.startsWith('/workspace');
        } else {
            return false;
        }
    }
}

import {Injectable} from '@angular/core';

@Injectable()
export class LabelsService {

    private labels = {
        'select.all': 'Select all',
        'deselect.all': 'Deselect all',
        search: 'Search'
    };

    static withLabels(labels: Object) {
        const newService = new LabelsService();
        for (const prop in labels) {
            newService.labels[prop] = labels[prop];
        }
        return newService;
    }

    getLabel(label: string) {
        return this.labels[label] || label;
    }

    mixin(labels: Object) {
        for (const property in labels) {
            this.labels[property] = labels[property];
        }
    }
}

import { Injectable, isDevMode } from '@angular/core';

@Injectable({
    providedIn: 'root'
})
export class Logger {

    debug(message: string, context: any, object?: any): void   {
        if (isDevMode()) {
            const logEntry = this.createLogStatement( message, context);
            console.log(`%c<${new Date().toLocaleString()}> %c[${context.constructor.name}] %c${'         ' + message || ''} %c`,
             'color:#398f3f',
             'color:#58c75f',
             'color:#6ee676',
             'color:#87f58e',
             object || '');
        }
    }

    error(message: string, context: any, object?: any): void {
        if (isDevMode()) {
            const logEntry = this.createLogStatement(message, context);
            console.error('         ' + logEntry, object || '');
        }
    }

    warn(message: string, context: any, object?: any): void  {
        if (isDevMode()) {
            const logEntry = this.createLogStatement( message, context);
            console.warn('         ' + logEntry, object || '');
        }
    }

    info(message: string, context: any, object?: any): void {
        if (isDevMode()) {
            const logEntry = this.createLogStatement(message, context);
            console.log(`%c<${new Date().toLocaleString()}> %c[${context.constructor.name}] %c${'         ' + message || ''} %c`,
             'color:#3293a8',
             'color:#09c3eb',
             'color:#78dede',
             'color:#78aede',
             object || '');
        }
    }

    createLogStatement(message,  context: any) {
        return `<${new Date().toLocaleString()}> [${context.constructor.name}] ${'         ' + message || ''} `;
    }

    constructor() {
        if (isDevMode()) {
            let text = '%c  ___                     ____  _       _ _        _ \n' +
            ' / _ \\ _ __   ___ _ __   |  _ \\(_) __ _(_) |_ __ _| |\n' +
            '| | | | ._ \\ / _ \\ ._ \\  | | | | |/ _` | | __/ _` | |\n' +
            '| |_| | |_) |  __/ | | | | |_| | | (_| | | || (_| | |\n' +
            ' \\___/| .__/ \\___|_| |_| |____/|_|\\__, |_|\\__\\__,_|_|\n' +
            ' _____|_| _                 _   _ |___/              \n' +
            '| ____|__| |_   _  ___ __ _| |_(_) ___  _ __         \n' +
            '|  _| / _. | | | |/ __/ _. | __| |/ _ \\| ._ \\        \n' +
            '| |__| (_| | |_| | (_| (_| | |_| | (_) | | | |       \n' +
            '|_____\\__,_|\\__,_|\\___\\__,_|\\__|_|\\___/|_| |_|       \n';
