import { RequireService } from './require/require.interface';
import { Parser } from './parser/parser.interface';
import { SijilOpts } from './sijil.opts';

/**
 * Defines a BundlesService, whice is the main entry point for Sijil operations.
 *
 * A BundlesServices has three dependencies :
 * - RequireService : Used to fetch bundles
 * - Parser : Used to parse logic inside bundle values
 * - SijilOpts : An object containing custom settings
 */
export class BundlesService {

    constructor(private requireService: RequireService, private parser: Parser, sijilOpts: SijilOpts) {
        this.defaultLanguage = sijilOpts.defaultLanguage;
        if(!this.defaultLanguage && typeof window !== 'undefined') {
            this.defaultLanguage = window.navigator.language.split('-')[0];
        }
        this.currentLanguage = this.defaultLanguage;
    }

    private bundles: Object = {};
    /**
     * Fallback language.
     */
    defaultLanguage: string;
    /**
     * Current language.
     */
    currentLanguage: string;

    /**
     * Add keys/values to an existing bundle, or create it if missing.
     *
     * @param bundle An object containing translations as key / values.
     * @param lang The language to map the bundle with, or the current langugage if omitted.
     */
    addToBundle(bundle: Object, lang?: string) : void {
        const targetLanguage = lang || this.currentLanguage || this.defaultLanguage || 'en';

        if(!this.bundles[targetLanguage]) {
            this.bundles[targetLanguage] = {};
        }

        this.bundles[targetLanguage] = Object.assign({}, this.bundles[targetLanguage], bundle);

        if(!this.currentLanguage) {
            this.currentLanguage = lang;
        }
    }

    /**
     * Loads a bundle and associates it with a language.
     * If the target language already contains key/values, then we mixin the new bundle and the existing one.
     *
     * @param where The path, or whatever the RequireService needs to fetch the bundle.
     * @param lang The target language, or the current language if omitted.
     * @returns A Promise, because the RequireService can be (is - by default) asynchronous.
     */
    loadBundle(where, lang?: string) : Promise<void> {
        return this.requireService.load(where)
            .then(bundle => {
                this.addToBundle(bundle, lang);
            })
    }
    /**
     * Loads multiple bundles and associates then with a language.
     *
     * @see {@link loadBundle}
     */
    loadBundles(specs: { lang: string, where: any }[]): Promise<void[]> {
        return Promise.all(specs.map((spec) => {
            return this.loadBundle(spec.where, spec.lang);
        }))
    }

    /**
     * Removes a bundle from the bundles list.
     *
     * @param lang Language to remove.
     */
    unloadBundle(lang: string): void {
        delete this.bundles[lang];
    }

    /**
     * @returns Returns a list of all loaded languages.
     */
    getLoadedLanguages() : string[] {
        return Object.keys(this.bundles);
    }

    /**
     * Translates a single key into a target language, using the parameters provided if needed.
     *
     * @param key Key to translate
     * @param parameters Parameters to use if the translation contains logic.
     * @param lang Target language, of the current language if omitted.
     * @returns The computed translation, or the key if no match was found in the bundles (including the fallback language bundle).
     */
    translate(key: string, parameters?: Object | any[], lang?: string) : string {
        const targetLanguage = lang || this.currentLanguage;

        const rawTranslation : string = this.bundles[targetLanguage] &&
            this.bundles[targetLanguage][key] ||
            this.defaultLanguage &&
            this.bundles[this.defaultLanguage] &&
            this.bundles[this.defaultLanguage][key] ||
            key;

        if(rawTranslation !== key && parameters) {
            return this.parser.compile(rawTranslation, parameters, (e) => { console.error(e); return key; });
        } else {
            return rawTranslation;
        }
    }
}

import {Type} from '@angular/core';

/**
* Usefull to desccribe (type and input data) a component
* that will be dynamically instanciate
*/
export class ComponentDescriptor {
   constructor(
       public type: Type<any>,
       public data: any
   ) {}

   assignData(data: any): ComponentDescriptor {
       Object.assign(this.data, data);
       return this;
   }
}

import { Parser, ParserCallback, ParserError } from './parser.interface';

/**
 * The default Sijil parser.
 *
 * - Input : bundle value (translation) + parameters (Object or Array)
 * - Output : compiled translation
 *
 * Logic is contained inside mustache blocks : {{ LOGIC BLOCK }}
 *
 * There are two variants :
 *  - A single parameter key (when the params are contained inside an object) or index (params contained inside an array)
 *
 * Examples:
 *
 * {{ key }} + { "key" : "my key" } = my key
 *
 * {{ 1 }} + [1, 2] = 2
 *
 *  - A ternary-like condition
 *
 * {{ condition ? trueValue : falseValue }}
 * Where condition may be : a single parameter key/index, or 2 clauses with the following operators : ==, >, =>, <=, <
 *
 * Examples:
 *
 * (the $ sign to refer to a variable is mandatory when a clause contains more than 1 word)
 *
 * {{ count > 1 ? $count cats : 1 cat }} + {"count": 10} = 10 cats
 * {{ 1 < count ? $count cats : 1 cat }} + {"count": 1} = 1 cat
 *
 * @export
 */
// @dynamic
export class FragmentsParser implements Parser {

    constructor(){}

    private static delimiters: string[] = ['{{', '}}'];
    private static delimRegexp = new RegExp(`${FragmentsParser.delimiters[0]}[^}]+${FragmentsParser.delimiters[1]}`, 'gm');

    private static defaultErrorCallback: ParserCallback = (e: ParserError) => {
        console.error(e);
        return e.fragment;
    }

    private getParameter(parameters: Object | any[], fragment: string, strict?: boolean): string {
        const splittedFrag = fragment.split(/\s+/);
        if(splittedFrag.length === 1) {
            return fragment[0] === '$' ?
                parameters[fragment.substr(1)] :
                strict ?
                    fragment :
                    parameters[fragment] !== undefined ?
                        parameters[fragment] :
                        fragment;
        }
        return fragment.split(/\s+/).reduce((l, r) => {
            l.push(r[0] === '$' ? parameters[r.substr(1)] : r);
            return l;
        }, []).join(' ');
    }

    private compileFragment(fragment: string, parameters: Object | any[]): string {
        fragment = fragment.replace(/{{|}}/g, '');

        let interrogationIndex;
        let dotsIndex;
        if ((interrogationIndex = fragment.indexOf('?')) > 0 && (dotsIndex = fragment.lastIndexOf(':')) > 1) {
            const condition = fragment.substring(0, interrogationIndex).trim();
            const trueReturn = fragment.substring(interrogationIndex + 1, dotsIndex).trim();
            const falseReturn = fragment.substring(dotsIndex + 1).trim();
            const computedTrueReturn = this.getParameter(parameters, trueReturn);
            const computedFalseReturn = this.getParameter(parameters, falseReturn);

            const splittedCondition = condition.split(/\s+/);

            if (splittedCondition.length === 1) {

                // Single variable case

                const variable = parameters[splittedCondition[0]];

                return variable ?
                    computedTrueReturn :
                    computedFalseReturn;

            } else if (splittedCondition.length === 3) {

                // Operator case

                const leftHandParam = this.getParameter(parameters, splittedCondition[0], parameters instanceof Array);
                const rightHand = this.getParameter(parameters, splittedCondition[2], parameters instanceof Array);
                const comparisonOperator = splittedCondition[1];

                switch (comparisonOperator) {
                    case '==':
                        return leftHandParam === rightHand ?
                            computedTrueReturn :
                            computedFalseReturn;
                    case '>':
                        return leftHandParam > rightHand ?
                            computedTrueReturn :
                            computedFalseReturn;
                    case '>=':
                        return leftHandParam >= rightHand ?
                            computedTrueReturn :
                            computedFalseReturn;
                    case '<':
                        return leftHandParam < rightHand ?
                            computedTrueReturn :
                            computedFalseReturn;
                    case '<=':
                        return leftHandParam <= rightHand ?
                            computedTrueReturn :
                            computedFalseReturn;
                    default:
                        throw new ParserError(`Invalid conditional operator for fragment : ${fragment}`, fragment);
                }

            } else {
                throw new ParserError(`Invalid condition for fragment : ${fragment}`, fragment);
            }
        } else {
            fragment = fragment.trim();
            return parameters[fragment];
        }
    }

    compile(rawTranslation: string, parameters: Object, onError?: ParserCallback): string {

        const parts = rawTranslation.split(FragmentsParser.delimRegexp);
        const fragments = rawTranslation.match(FragmentsParser.delimRegexp);

        let compiledTranslation = '';

        if (!onError) {
            onError = FragmentsParser.defaultErrorCallback;
        }

        if (!fragments) {
            compiledTranslation += rawTranslation;
        } else {
            for (let i = 0; i < parts.length; i++) {
                compiledTranslation += parts[i];
                if (i > fragments.length - 1) {
                    continue;
                }
                try {
                    compiledTranslation += this.compileFragment(fragments[i], parameters);
                } catch (e) {
                    compiledTranslation += onError(e);
                }
            }
        }

        return compiledTranslation;

    }

}

export class ParserError extends Error {
    constructor(public message: string, public fragment: string) {
        super(message)
    }
}

export type ParserCallback = (_ : ParserError) => string;
/**
 * Parses logic inside translations.
 *
 * @export
 */
export abstract class Parser {
    /**
     * Processes a string, isolating logic fragments and compiling them.
     *
     * @memberOf Parser
     */
    compile: (text: string, parameters: any, error?: ParserCallback) => string;
}

export class ParserError extends Error {
    constructor(public message: string, public fragment: string) {
        super(message)
    }
}

export type ParserCallback = (_ : ParserError) => string;
/**
 * Parses logic inside translations.
 *
 * @export
 */
export abstract class Parser {
    /**
     * Processes a string, isolating logic fragments and compiling them.
     *
     * @memberOf Parser
     */
    compile: (text: string, parameters: any, error?: ParserCallback) => string;
}

export abstract class RequireService {
    /**
     * Fetch a bundle.
     * @memberOf RequireService
     */
    load: (from: any) => Promise<Object>;
}

export abstract class SijilOpts {
    /** Fallback language when a translation is not available in the current language. */
    defaultLanguage: string;
}

export let defaultSijilOpts : SijilOpts = {
    defaultLanguage: window ? window.navigator.language.split('-')[0] : undefined
};

import { RequireService } from './require.interface'

export class XHRRequire implements RequireService {

    load(from: string, async?: boolean) : Promise<Object>{
        return new Promise((resolve, reject) => {
            let request = new XMLHttpRequest()

            request.open('GET', from, !async)
            request.responseType = "json"
            request.onload = function(e) {
                if(request.status === 200){
                    let json = request.response
                    resolve(json)
                } else {
                    console.log('Unsupported language.')
                }
            }
            request.onerror = function(e) {
                console.error(e)
            }
            request.send()
        })
    }

}

