import {Directive, HostListener, Input} from '@angular/core';

@Directive({ selector: '[anchor]' })
export class AnchorDirective {

    @Input('anchor') anchor: string;
    @Input('offset') offset = 50;

    @HostListener('click')
    onClick() {
        const element = document.getElementById(this.anchor);
        window.scrollBy(0, element.getBoundingClientRect().top - this.offset);
    }

}

import {Directive, EventEmitter, HostBinding, HostListener, Input, Output} from '@angular/core';
import {InputFileService} from '../services/inputFile.service';

@Directive({
    selector: '[dragAndDropFiles]'
})
export class DragAndDropFilesDirective {
    @Input()
    allowedExtensions: Array<string> = [];
    @Input()
    maxFilesNumber = 1;
    @Input()
    disabled: boolean;

    @Output()
    dragAndDrop: EventEmitter<File[]> = new EventEmitter();
    @Output()
    invalidDragAndDrop: EventEmitter<string> = new EventEmitter();

    @HostBinding('style.background')
    public backgroundColor = '#fafafa';
    @HostBinding('style.border-color')
    public borderColor = '#ddd';

    constructor(private inputFileService: InputFileService) {
    }

    @HostListener('dragover', ['$event'])
    public onDragOver(evt) {
        if (!this.disabled) {
            evt.preventDefault();
            evt.stopPropagation();
            this.highlightColors();
        }
    }

    @HostListener('dragleave', ['$event'])
    public onDragLeave(evt) {
        if (!this.disabled) {
            evt.preventDefault();
            evt.stopPropagation();
            this.resetColors();
        }
    }

    @HostListener('drop', ['$event'])
    public onDrop(event) {
        if (!this.disabled) {
            event.preventDefault();
            event.stopPropagation();

            if (event.dataTransfer) {
                this.inputFileService
                    .validateFiles(event.dataTransfer.files, this.maxFilesNumber, this.allowedExtensions)
                    .subscribe(files => this.dragAndDrop.emit(files)
                        , error => this.invalidDragAndDrop.emit(error));
            }

            this.resetColors();
        }
    }

    private resetColors() {
        this.backgroundColor = '#fafafa';
        this.borderColor = '#ddd';
    }

    private highlightColors() {
        this.backgroundColor = '#ffd1b6';
        this.borderColor = '#ff8352';
    }
}

import {ComponentFactoryResolver, ComponentRef, Directive, Input, ViewContainerRef, } from '@angular/core';
import {ComponentDescriptor} from './component-descriptor.model';

/**
* Dynamically load the component describe with the @input dynamic-component
*/
@Directive({
    selector: '[dynamic-component]',
})
export class DynamicComponentDirective {
    constructor(
        private viewContainerRef: ViewContainerRef,
        private componentFactoryResolver: ComponentFactoryResolver
    ) {}

    public componentRef: ComponentRef<any>;

    @Input('dynamic-component')
    componentDesc: ComponentDescriptor;

    load(data?: any): void {
        if (this.isLoaded()) { return; }
        const componentFactory = this.componentFactoryResolver.resolveComponentFactory(this.componentDesc.type);
        this.viewContainerRef.clear();
        this.componentRef = this.viewContainerRef.createComponent(componentFactory);

        if (data != undefined) {
            this.componentDesc.assignData(data);
        }
        for (const attribute in this.componentDesc.data) {
            this.componentRef.instance[attribute] = this.componentDesc.data[attribute];
            if (attribute == 'hideEvent') {
                this.componentRef.instance.hideEvent.subscribe(e => {
                    this.destroy();
                });
            }
        }
    }

    isLoaded(): boolean {
        if (this.componentRef == undefined) {
            return false;
        }
        else {
            return this.componentRef.instance != null;
        }
    }

    destroy(): void {
        if (this.componentRef.instance.hideEvent != undefined) {
            this.componentRef.instance.hideEvent.unsubscribe();
        }
        // FIXME: this.componentRef.destroy(); => This one usually should work, better to use but do nothing...
        delete this.componentRef;
        this.viewContainerRef.clear();
    }
}

import {Compiler, Component, Directive, ElementRef, Input, NgModule, Injector, Type, ViewContainerRef} from '@angular/core';

import {CommonModule} from '@angular/common';
import {DynamicModuleImportsService} from '../services/dynamicModuleImports.service';

@Directive({
    selector: 'dynamic-template'
})
export class DynamicTemplateDirective {

    constructor(
        private elementRef: ElementRef,
        private viewContainer: ViewContainerRef,
        private compiler: Compiler,
        private dynamicModuleImports: DynamicModuleImportsService
    ) {}

    @Input('template')
    set templateContents(html: string) {
        if (html) {
            this._html = html;
            const cmpType = this._createDynamicComponent();
            const moduleType = this._createDynamicModule(cmpType);
            const injector: Injector = Injector.create({
                providers: [],
                parent: this.viewContainer.parentInjector,
            });

            this.compiler.compileModuleAndAllComponentsAsync<any>(moduleType)
                .then(factory => {
                    let cmpFactory: any;
                    for (let i = factory.componentFactories.length - 1; i >= 0; i--) {
                        if (factory.componentFactories[i].selector === this._selector) {
                            cmpFactory = factory.componentFactories[i];
                            break;
                        }
                    }
                    return cmpFactory;
                })
                .then(cmpFactory => {
                    if (cmpFactory && this.viewContainer) {
                        this.viewContainer.clear();
                        this.viewContainer.createComponent(cmpFactory, 0, injector);
                    }
                });
        } else {
            this._html = '';
            this.viewContainer.clear();
        }
    }

    private _html = '';
    private _selector = 'dynamic-view';

    @Input() private context: Object;

    private _createDynamicComponent(): Type<any> {
        const metadata = {
            selector: this._selector,
            template: this._html,
            inputs: ['template']
        };
        class _cmp_ {}
        _cmp_.prototype = this.context;
        return Component(metadata)(_cmp_);
    }

    private _createDynamicModule(componentType: Type<any>) {
        class _mod_ {}
        return NgModule({
            imports: [
                CommonModule,
                ...this.dynamicModuleImports.imports ],
            declarations: [componentType],
            providers: []
        })(_mod_);
    }

}

import {Directive, ElementRef} from '@angular/core';

/**
*
* see https://developer.mozilla.org/en-US/docs/Web/API/URL/createObjectURL
*/
@Directive({ selector: '[object-url]' })
export class ObjectURLDirective {

    constructor(
        private elementRef: ElementRef,
    ) {}

    private objectURL;

    // TODO provide more specific method like createJSON, createCSV, createPDF
    // to free directive consumer from using Blog API
    create(blob: Blob, filename: string): void {
        if (this.objectURL !== null) {
            window.URL.revokeObjectURL(this.objectURL);
        }
        this.objectURL = window.URL.createObjectURL(blob);
        this.elementRef.nativeElement.href = this.objectURL;
        this.elementRef.nativeElement.download = filename;
    }

}

