import { Component, Input, ElementRef, ViewChild, AfterViewInit, ChangeDetectionStrategy, DoCheck } from '@angular/core';
import { BundlesService } from '../services/bundles.service';

@Component({
    selector: 's5l',
    template: `
    <span #wrapper>
        <ng-content></ng-content>
    </span>`,
    changeDetection: ChangeDetectionStrategy.OnPush
})
export class S5lComponent implements AfterViewInit, DoCheck {

    constructor(private bundlesService: BundlesService) {}

    @ViewChild('wrapper') wrapperRef: ElementRef;

    private value: string;
    private loaded: boolean;
    private displayedValue: string;

    @Input("s5l-params") parameters: Object | any[];
    @Input("s5l-lang") fixedLanguage: string;

    private refreshTranslation() {
        const newDisplayedValue = this.bundlesService.translate(this.value, this.parameters, this.fixedLanguage)
        if (this.displayedValue !== newDisplayedValue) {
            this.displayedValue = newDisplayedValue;
            this.wrapperRef.nativeElement.innerHTML = this.displayedValue;
        }
    }

    ngAfterViewInit(): void {
        this.value = this.wrapperRef.nativeElement.innerHTML.trim();
        this.loaded = true;
        this.refreshTranslation();
    }

    ngDoCheck(): void {
        if (!this.loaded) {
            return;
        }
        this.refreshTranslation();
    }
}

import { OdeComponent } from 'ngx-ode-core';
import { Component, ElementRef, EventEmitter, Input, OnDestroy, OnInit, Output, Renderer2, ViewChild, Injector } from '@angular/core';
import {Observable, Subject, Subscription} from 'rxjs';
import {debounceTime, distinctUntilChanged} from 'rxjs/operators';


@Component({
    selector: 'ode-search-input',
    templateUrl: './search-input.component.html',
    styleUrls: ['./search-input.component.scss']
})
export class SearchInputComponent extends OdeComponent implements OnInit, OnDestroy {

    constructor(injector: Injector,
                private _elRef: ElementRef,
                private _renderer: Renderer2) {
        super(injector);
    }

    /* Inputs / Outputs / View */
    @Input() isSearchActive: boolean = false;
    @Input() searchInput: boolean = false;
    @Input() searchSubmit: () => void;
    @Input() set delay(d: number) {
        this._delay = d;
        this.observable = this.$searchTerms.pipe(debounceTime(this.delay), distinctUntilChanged());
        if (this.observer) {
            this.observer.unsubscribe();
        }
        this.observer = this.observable.subscribe(val => {
            this.onChange.emit(val);
        });
    }
    get delay() {
        return this._delay;
    }
    private _delay = 200;

    @Output() onChange: EventEmitter<string> = new EventEmitter<string>();

    @ViewChild('searchBox') searchBox: ElementRef;

    /* Internal logic */

    private $searchTerms = new Subject<string>();
    private observable: Observable<string>;
    private observer: Subscription;

    private evalAttributes() {
        const element = this._elRef.nativeElement;
        if (element && this.searchBox) {
            for (let i = 0; i < element.attributes.length; i++) {
                const attr = element.attributes[i];
                this._renderer.setAttribute(this.searchBox.nativeElement, attr.name, attr.value);
            }
        }
    }

    ngOnInit(): void {
        super.ngOnInit();
        if (!this.observable) {
            this.observable = this.$searchTerms
                .pipe(
                    debounceTime(this.delay),
                    distinctUntilChanged()
                );
            this.observer = this.observable.subscribe(val => {
                this.onChange.emit(val);
            });
        }
        setTimeout(() => this.evalAttributes(), 20);
    }

    ngOnDestroy(): void {
        super.ngOnDestroy();
        this.observer.unsubscribe();
    }

    search(str: string) {
        this.$searchTerms.next(str);
    }

}

